s($,"bcC","aSm",()=>A.b([A.tt("Official Observe platform documentation.","Observe Documentation","https://docs.observeinc.com"),A.tt("Complete OPAL language reference guide.","OPAL Reference","https://docs.observeinc.com/en/latest/content/query/opal-reference.html"),A.tt("Community forums for questions and best practices.","Observe Community","https://community.observeinc.com"),A.tt("OpenTelemetry project \u2014 observability framework.","OpenTelemetry","https://opentelemetry.io"),A.tt("Check Observe platform availability and incidents.","Observe Status Page","https://status.observeinc.com"),A.tt("Open-source integrations and examples.","Observe GitHub","https://github.com/observeinc"),A.tt("Snowflake \u2014 the AI Data Cloud.","Snowflake","https://www.snowflake.com"),A.tt("Interactive FAQ companion app for Observe.","Observe FAQs Streamlit App","https://observe-faqs.streamlit.app")],A.a_("r<xw>")))
